@Test public void siblingElementsWithSingleChild() {
    Document doc = Jsoup.parse("<div><p>Only</p></div>");
    Element p = doc.select("p").first();
    Elements siblings = p.siblingElements();
    assertEquals(0, siblings.size());
}

@Test public void siblingNodesWithSingleChild() {
    Document doc = Jsoup.parse("<div><p>Only</p></div>");
    Element p = doc.select("p").first();
    List<Node> siblings = p.siblingNodes();
    assertEquals(0, siblings.size());
}

@Test public void siblingElementsFirstChild() {
    Document doc = Jsoup.parse("<div><p>First</p><p>Second</p><p>Third</p></div>");
    Element p1 = doc.select("p").get(0);
    Elements siblings = p1.siblingElements();
    assertEquals(2, siblings.size());
    assertEquals("<p>Second</p>", siblings.get(0).outerHtml());
    assertEquals("<p>Third</p>", siblings.get(1).outerHtml());
}

@Test public void siblingElementsLastChild() {
    Document doc = Jsoup.parse("<div><p>First</p><p>Second</p><p>Third</p></div>");
    Element p3 = doc.select("p").get(2);
    Elements siblings = p3.siblingElements();
    assertEquals(2, siblings.size());
    assertEquals("<p>First</p>", siblings.get(0).outerHtml());
    assertEquals("<p>Second</p>", siblings.get(1).outerHtml());
}
